/** biome-ignore-all lint/correctness/useExhaustiveDependencies: intentional dependency omission */
import { PublicActionPage } from '@domain/publicActionPage';
import { AddressFieldProps } from '@pages/ActionPages/pages/ActionPagesBuilder/components/ActionPage/ActionPageForm/Fields/Address/Address';
import { useGetIsFreeTickets } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks/useGetIsFreeTickets';
import { useTotalAmount } from '@pages/ActionPages/pages/PublicActionPage/ActionPageView/ActionPageLayout/ActionPageBody/hooks/useTotalAmount';
import { DonorProfileResponse } from '@state/user/donor_profile';
import { formatName } from '@ui/utils';
import { useEffect } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { LocationIcon } from '../../../icons';
import { Meta } from '../../../Meta';
import { SignedInSection } from '../SignedInSection';

type Props = Pick<AddressFieldProps, 'fieldPrefix' | 'fieldPrefixDelimiter'> & {
  actionPage: PublicActionPage;
  donorProfile: DonorProfileResponse;
};

export const AddressSection = ({
  actionPage,
  donorProfile,
  fieldPrefix = '',
  fieldPrefixDelimiter = '',
}: Props) => {
  const { t } = useTranslation('customFields', { keyPrefix: 'address' });
  const { setValue, trigger } = useFormContext();
  const { city, country, firstName, lastName, line1, line2, postalCode, region } = donorProfile;
  const addressLabel = actionPage.fieldConfiguration?.addressLabel;
  const isFreeTickets = useGetIsFreeTickets(actionPage);
  const donationAmount = useTotalAmount();

  useEffect(() => {
    // only trigger when paid tickets or general donation are selected
    if (actionPage.fieldConfiguration?.displayAddress && (!isFreeTickets || donationAmount > 0)) {
      if (actionPage.fieldConfiguration.addressType === 'zip') {
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}postalCode`, postalCode);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}postalCode`);
      } else {
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}line1`, line1);
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}line2`, line2 || '');
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}city`, city);
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}region`, region);
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}country`, country);
        setValue(`${fieldPrefix}${fieldPrefixDelimiter}postalCode`, postalCode);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}line1`);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}line2`);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}city`);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}region`);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}country`);
        trigger(`${fieldPrefix}${fieldPrefixDelimiter}postalCode`);
      }
    } else {
      // set address attributes to null when free tickets are selected as they are not needed
      setValue(`${fieldPrefix}`, null);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}line1`);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}line2`);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}city`);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}region`);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}country`);
      trigger(`${fieldPrefix}${fieldPrefixDelimiter}postalCode`);
    }
  }, [isFreeTickets]);

  if (
    !actionPage.fieldConfiguration?.displayAddress ||
    (!firstName && !lastName && !line1 && !line2 && !city && !region && !postalCode && !country)
  ) {
    return null;
  }

  return (
    <SignedInSection icon={<LocationIcon />}>
      <div className="flex grow flex-col">
        <Meta className="text-[13px] leading-4 !text-neutral-500" variant="regular">
          {addressLabel ? t(`${addressLabel}`) : t('street')}
        </Meta>
        <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
          {formatName({ firstName, lastName })}
        </Meta>
        <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
          {line1}
        </Meta>
        {line2 ? (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {line2}
          </Meta>
        ) : null}
        {city && region && (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {city}, {region} {postalCode}
          </Meta>
        )}
        {!city && !region && postalCode && (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {postalCode}
          </Meta>
        )}
        {country ? (
          <Meta className="text-base text-p leading-[17px] text-neutral-700" variant="regular">
            {country}
          </Meta>
        ) : null}
      </div>
    </SignedInSection>
  );
};

